// Analyze chat logs and generate summary statistics
const items = $input.all();

// Initialize counters
let totalQuestions = 0;
let filesReferenced = {};
let failedLookups = 0;

// Process each chat log entry
for (const item of items) {
  const data = item.json;

  // Count total questions
  totalQuestions++;

  // Track files referenced (if available in the data)
  if (data.filesReferenced) {
    const files = Array.isArray(data.filesReferenced) ? data.filesReferenced : [data.filesReferenced];
    files.forEach(file => {
      filesReferenced[file] = (filesReferenced[file] || 0) + 1;
    });
  }

  // Count failed lookups (if no relevant documents found)
  if (data.documentsFound === 0 || data.status === 'failed' || data.noResults === true) {
    failedLookups++;
  }
}

// Sort files by reference count
const topFiles = Object.entries(filesReferenced)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 10)
  .map(([file, count]) => ({ file, count }));

// Calculate success rate
const successRate = totalQuestions > 0 ? ((totalQuestions - failedLookups) / totalQuestions * 100).toFixed(2) : 0;

// Generate HTML email body
const topFilesHtml = topFiles.length > 0 
  ? topFiles.map(({ file, count }) => `<li><strong>${file}</strong>: ${count} references</li>`).join('')
  : '<li>No files referenced</li>';

const emailBody = `
<!DOCTYPE html>
<html>
<head>
  <style>
    body { font-family: Arial, sans-serif; line-height: 1.6; color: #333; }
    .container { max-width: 600px; margin: 0 auto; padding: 20px; }
    .header { background-color: #4CAF50; color: white; padding: 20px; text-align: center; border-radius: 5px; }
    .stats { background-color: #f4f4f4; padding: 15px; margin: 20px 0; border-radius: 5px; }
    .stat-item { margin: 10px 0; }
    .stat-label { font-weight: bold; color: #555; }
    .stat-value { color: #4CAF50; font-size: 1.2em; }
    .success-rate { font-size: 2em; color: #4CAF50; font-weight: bold; }
    ul { padding-left: 20px; }
    .footer { margin-top: 30px; padding-top: 20px; border-top: 1px solid #ddd; font-size: 0.9em; color: #777; }
  </style>
</head>
<body>
  <div class="container">
    <div class="header">
      <h1>📊 Daily RAG Chatbot Summary</h1>
      <p>${new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}</p>
    </div>

    <div class="stats">
      <div class="stat-item">
        <span class="stat-label">Total Questions Asked:</span>
        <span class="stat-value">${totalQuestions}</span>
      </div>

      <div class="stat-item">
        <span class="stat-label">Success Rate:</span>
        <div class="success-rate">${successRate}%</div>
      </div>

      <div class="stat-item">
        <span class="stat-label">Failed Lookups:</span>
        <span class="stat-value">${failedLookups}</span>
      </div>

      <div class="stat-item">
        <span class="stat-label">Total Files Referenced:</span>
        <span class="stat-value">${Object.keys(filesReferenced).length}</span>
      </div>
    </div>

    <h2>📁 Top Referenced Files</h2>
    <ul>
      ${topFilesHtml}
    </ul>

    <div class="footer">
      <p>This is an automated summary generated by your RAG Chatbot system.</p>
    </div>
  </div>
</body>
</html>
`;

// Return summary statistics with email body
return [{
  json: {
    totalQuestions,
    topFilesReferenced: topFiles,
    failedLookups,
    successRate: `${successRate}%`,
    totalFilesReferenced: Object.keys(filesReferenced).length,
    summaryDate: new Date().toISOString().split('T')[0],
    emailBody
  }
}];
